  ('optometrist-moex-01004', 'optometrist', 'optometrist-moex-111-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於鏡架的前傾角和後傾斜，下列何者錯誤？', '["前傾角是指配戴眼鏡時，鏡架前框平面與臉部前表面所形成的角度", "鼻墊的垂直角度會影響前傾角", "鏡架前框的頂部較底部更靠近配戴者的臉部平面表示有後傾斜", "調整眼鏡架成為後傾狀態，較前傾為佳"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "314843536d18", "answer_pdf_sha1": "1d5aa7eb2e69", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01005', 'optometrist', 'optometrist-moex-111-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關稜鏡之敘述，下列何者錯誤？', '["稜鏡製作時稜鏡偏向角之誤差值（deviationangle’serrorofprism）須小於5%", "稜鏡之偏向與其頂角有關，與折射率無關", "P∆ =100×tand；d= 偏向角（deviationangle）", "偏向角 4 度約等於 7 個稜鏡度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "314843536d18", "answer_pdf_sha1": "1d5aa7eb2e69", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01006', 'optometrist', 'optometrist-moex-111-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '患者眼鏡度數分別為OD：-4.25DS/-1.50DC×180，OS：+0.50DS/-1.25DC×180，其眼鏡被小孩弄歪往他 的右邊偏4mm，且向下滑落3mm。此時患者雙眼同時看出去時感受的稜鏡效應為何？', '["右眼有1.5∆基底朝外，同時左眼有1.5∆基底朝上", "左眼有1.5∆基底朝外，同時右眼有1.5∆基底朝上", "右眼有1.9∆基底朝內，同時左眼有1.5∆基底朝下", "左眼有1.9∆基底朝外，同時右眼有1.5∆基底朝下"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "314843536d18", "answer_pdf_sha1": "1d5aa7eb2e69", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01007', 'optometrist', 'optometrist-moex-111-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關半自動驗度儀（lensometer）之敘述，下列何者錯誤？', '["目鏡（eyepiece）需要在使用前先對焦", "透過散光軸度轉輪（cylinderaxiswheel）可以知道散光度數的軸度與稜鏡度", "透鏡夾（lensstop）可以夾住鏡片穩定放置到載鏡平台（spectacletable）上", "光學標記器（inkmarker）可以打點到在鏡片上標記光學中心點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "314843536d18", "answer_pdf_sha1": "1d5aa7eb2e69", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01008', 'optometrist', 'optometrist-moex-111-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '患者處方為OD：-8.50DS/-0.75DC×180，OS：-9.50DS/-0.50DC×180使用1.67非球面鏡片，單眼瞳距右 眼30mm左眼31mm，配鏡十字的高度右眼22mm左眼20mm，鏡框尺寸為43□23-142，B尺寸為42， 則每片鏡片的水平移心量與垂直移心量為何？', '["水平移心量：右眼外移2mm，左眼外移3mm；垂直移心量：右眼上移1mm，左眼上移2mm", "水平移心量：右眼內移3mm，左眼內移2mm；垂直移心量：右眼下移1mm，左眼上移1mm", "水平移心量：右眼內移3mm，左眼內移2mm；垂直移心量：右眼上移1mm，左眼下移1mm", "水平移心量：右眼內移2mm，左眼內移3mm；垂直移心量：右眼下移1mm，左眼下移1mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "314843536d18", "answer_pdf_sha1": "1d5aa7eb2e69", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01009', 'optometrist', 'optometrist-moex-111-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '患者加入度為+2.00DS，使用雙光子片時，雙眼各需加入1.00∆基底朝外的稜鏡，若要透過改變子片的位置 來提供稜鏡量，則應該如何調整？', '["右眼子片向鼻側偏移5mm，左眼子片向耳側偏移5mm", "右眼子片向耳側偏移5mm，左眼子片向鼻側偏移5mm", "雙眼子片皆向耳側偏移5mm", "雙眼子片皆向鼻側偏移5mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "314843536d18", "answer_pdf_sha1": "1d5aa7eb2e69", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01010', 'optometrist', 'optometrist-moex-111-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '一患者右眼度數為OD：+2.00DS/-2.00DC×090，左眼度數為OS：+1.00DS/-1.00DC×090，主要參考點高 度為24mm，鏡框垂直尺寸（B）為50mm，則產生的稜鏡效應為何？', '["右眼為0.4∆基底向上，左眼0.2∆基底向下", "右眼為0.2∆基底向下，左眼0.2∆基底向上", "右眼為0.1∆基底向下，左眼0.1∆基底向下", "右眼為0.2∆基底向上，左眼0.1∆基底向上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "314843536d18", "answer_pdf_sha1": "1d5aa7eb2e69", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01011', 'optometrist', 'optometrist-moex-111-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '在不等視驗配中，下列何者不會改變眼鏡放大率？', '["改變鏡片頂點距離", "降低鏡片厚度", "使用高折射率鏡片", "改變瞳距"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:44+00:00", "source_pdf_sha1": "314843536d18", "answer_pdf_sha1": "1d5aa7eb2e69", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "111", "s": "1004", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
